1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Basic premium calculation ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("single sword (no modifiers, newcomer first contract) → 100 base + 10 first + 5 fee = 115 G");
14	  it.todo("single amulet (no modifiers, newcomer first contract) → 60 + 6 + 5 = 71 G");
15	  it.todo("single staff (no modifiers, newcomer first contract) → 80 + 8 + 5 = 93 G");
16	  it.todo("single potion (no modifiers, newcomer first contract) → 40 + 4 + 5 = 49 G");
17	
18	  // --- Components and block discount ---
19	  it.todo("2 runes → base 50 G (no block)");
20	  it.todo("3 runes → base 60 G (block applies)");
21	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
22	  it.todo("7 runes → base 175 G (no block at 7)");
23	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
24	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
25	
26	  // --- Item-specific modifiers ---
27	  it.todo("cursed sword newcomer first contract → 100 + 50 curse + 10 first + 5 fee = 165 G");
28	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
29	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
30	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
31	
32	  // --- Policy-wide modifiers ---
33	  it.todo("customer with exactly 2 years → loyalty discount applies");
34	  it.todo("second contract → follow-up discount applies");
35	
36	  // --- Modifier scope on multi-item policy ---
37	  it.todo("cursed sword + plain amulet → policy base 160 + 50 curse = 210 G before fee/policy-wide");
38	
39	  // --- Rounding ---
40	  it.todo("premium yielding 197.5 G → rounded up to 198 G");
41	  it.todo("payout yielding 350.5 G → rounded down to 350 G");
42	
43	  // --- Integration examples ---
44	  it.todo("newcomer with cursed sword (enchantment 3) → 165 G");
45	  it.todo("long-standing customer (3y) second contract, cursed sword enchantment 7 → 160 G");
46	
47	  // --- Claim: basic and deductible ---
48	  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
49	  it.todo("rune (no enchantment/material) damage 200 G → payout 100 G");
50	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
51	
52	  // --- Claim: enchantment and dragon clauses ---
53	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (50% then deductible)");
54	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
55	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (full, then deductible)");
56	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");
57	
58	  // --- Multiple items of the same type ---
59	  it.todo("policy with two swords, both damaged → each treated as separate damage with own deductible");
60	  it.todo("damages array has more entries of a type than policy covers → CLI rejects whole claim");
61	
62	  // --- Cap exhaustion ---
63	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
64	  it.todo("cursed sword premium modifiers do not raise cap → cap remains 2000");
65	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block does not reduce insurance sum)");
66	  it.todo("sword cap 2000: two claims of 1500 → first payout 1400 (cap 600), second payout 600 (cap 0)");
67	
68	  // --- Edge cases / CLI errors ---
69	  it.todo("quote with unknown item type → CLI exits non-zero, writes stderr, no results");
70	  it.todo("claim references item not in policy → CLI exits non-zero, writes stderr");
71	  it.todo("claim damage with negative amount → CLI exits non-zero, writes stderr");
72	});
